def HTML_cleaner(src):
    try:
        src = str(src)
        if ('&amp;' in src): src = src.replace('&amp;', '&')
        if ('&lt;' in src): src = src.replace('&lt;', '<')
        if ('&gt;' in src): src = src.replace('&gt;', '>')
        return str(src)
    except:
        return str(src)

