def SMTP_Login(smtp_line, your_email, your_code):
    server = None
    ALLOW_INVALID_SSL = True
    try:
        parts = [x.strip() for x in smtp_line.strip().split('|', 3)]
        if (len(parts) != 4): return 'BAD-FORM'
        smtp_server, smtp_port, smtp_user, smtp_password = parts
        usr = smtp_user.split('@')[0]
        usr_domain = smtp_user.split('@')[1]
        subject = "Sending Test {}-{} {}".format(usr, usr_domain, your_code)
        body = "it's Just sending Test usr: {} {}".format(usr, your_code)
        smtp_port = int(smtp_port)
        msg = EmailMessage()
        msg["From"] = smtp_user
        msg["To"] = your_email
        msg["Subject"] = subject
        msg["Message-ID"] = make_msgid()
        msg.set_content(body,subtype="plain", charset="utf-8")
        context = ssl.create_default_context()
        if (ALLOW_INVALID_SSL):
            context.check_hostname = False
            context.verify_mode = ssl.CERT_NONE
        if (smtp_port == 465):
            server = smtplib.SMTP_SSL(smtp_server, smtp_port, timeout=60, context=context)
            server.ehlo()
        else:
            server = smtplib.SMTP(smtp_server, smtp_port, timeout=60)
            server.ehlo()
            if (server.has_extn("starttls")):
                server.starttls(context=context)
                server.ehlo()
        server.login(smtp_user,smtp_password)
        server.sendmail(smtp_user, [your_email], msg.as_string())
        return True
    except Exception:
        return False
    finally:
        if (server):
            try:
                server.quit()
            except Exception:
                pass

